async (params, browser) => {
  // Parse events JSON and build eventedit URLs
  const items = await browser.evaluate(`const events = JSON.parse(params.events_json); return events.map(e => { const title = e.title || 'Untitled Event'; const date = (e.date || '').replace(/-/g, ''); const dur = parseInt(e.duration) || 60; let dates = ''; if (e.time && date) { const [h, m] = e.time.split(':'); const startMin = parseInt(h) * 60 + (parseInt(m) || 0); const endMin = startMin + dur; const endH = String(Math.floor(endMin / 60) % 24).padStart(2, '0'); const endM = String(endMin % 60).padStart(2, '0'); dates = date + 'T' + String(h).padStart(2, '0') + String(m || '00').padStart(2, '0') + '00/' + date + 'T' + endH + endM + '00'; } else if (date) { const d = new Date(parseInt(date.slice(0,4)), parseInt(date.slice(4,6))-1, parseInt(date.slice(6,8))+1); const next = d.getFullYear() + String(d.getMonth()+1).padStart(2,'0') + String(d.getDate()).padStart(2,'0'); dates = date + '/' + next; } const p = new URLSearchParams(); p.set('text', title); if (dates) p.set('dates', dates); if (e.description) p.set('details', e.description); return { url: 'https://calendar.google.com/calendar/r/eventedit?' + p.toString(), title: title, date: e.date || '', time: e.time || '' }; })`)

  // Create each event in a parallel tab
  // TODO: Unsupported step type "forEachItem"

  return items
}
